Chào bạn, tôi là Dev Agent. Dựa trên bản thiết kế chi tiết mà bạn đã cung cấp, tôi sẽ triển khai mã nguồn cho hệ thống **express-jwt-mongodb-auth-app** theo đúng cấu trúc layered architecture và các tiêu chuẩn bảo mật đã đề ra.

### 1. Cấu trúc thư mục (Project Structure)
```text
express-jwt-mongodb-auth-app/
├── src/
│   ├── config/         # Cấu hình DB và biến môi trường
│   ├── controllers/    # Xử lý logic nghiệp vụ
│   ├── middlewares/    # Middleware xác thực và xử lý lỗi
│   ├── models/         # Schema Mongoose
│   ├── routes/         # Định nghĩa các endpoint API
│   └── app.js          # Cấu hình Express app
├── .env                # Biến môi trường
├── .gitignore
├── package.json
└── server.js           # Điểm khởi đầu của ứng dụng
```

### 2. Cài đặt Dependencies
Bạn cần khởi tạo project và cài đặt các thư viện sau:
```bash
npm init -y
npm install express mongoose jsonwebtoken bcryptjs dotenv
npm install --save-dev nodemon
```

### 3. Triển khai mã nguồn

#### 3.1. Cấu hình môi trường (`.env`)
```env
PORT=5000
MONGODB_URI=mongodb://localhost:27017/auth_db
JWT_SECRET=your_super_secret_key_12345
```

#### 3.2. Kết nối Database (`src/config/db.js`)
```javascript
const mongoose = require('mongoose');

const connectDB = async () => {
    try {
        await mongoose.connect(process.env.MONGODB_URI);
        console.log('✅ MongoDB Connected...');
    } catch (err) {
        console.error('❌ Database Connection Error:', err.message);
        process.exit(1);
    }
};

module.exports = connectDB;
```

#### 3.3. Model Người dùng (`src/models/User.js`)
```javascript
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

const UserSchema = new mongoose.Schema({
    username: {
        type: String,
        required: [true, 'Vui lòng nhập tên đăng nhập'],
        unique: true,
        trim: true,
        lowercase: true
    },
    password: {
        type: String,
        required: [true, 'Vui lòng nhập mật khẩu'],
        minlength: 6
    }
}, { timestamps: true });

// Middleware băm mật khẩu trước khi lưu
UserSchema.pre('save', async function(next) {
    if (!this.isModified('password')) return next();
    const salt = await bcrypt.genSalt(10);
    this.password = await bcrypt.hash(this.password, salt);
    next();
});

// Phương thức so sánh mật khẩu
UserSchema.methods.comparePassword = async function(candidatePassword) {
    return await bcrypt.compare(candidatePassword, this.password);
};

module.exports = mongoose.model('User', UserSchema);
```

#### 3.4. Middleware Xác thực (`src/middlewares/auth.js`)
```javascript
const jwt = require('jsonwebtoken');

const auth = (req, res, next) => {
    // 1. Lấy token từ header Authorization
    const authHeader = req.header('Authorization');
    const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>

    if (!token) {
        return res.status(401).json({ message: 'Không có token, quyền truy cập bị từ chối' });
    }

    try {
        // 2. Xác thực và giải mã token
        const decoded = jwt.verify(token, process.env.JWT_SECRET);

        // 3. Gắn thông tin user vào request
        req.user = decoded;
        next();
    } catch (err) {
        res.status(401).json({ message: 'Token không hợp lệ hoặc đã hết hạn' });
    }
};

module.exports = auth;
```

#### 3.5. Controllers (`src/controllers/authController.js`)
```javascript
const User = require('../models/User');
const jwt = require('jsonwebtoken');

// Đăng ký người dùng
exports.register = async (req, res) => {
    try {
        const { username, password } = req.body;

        // Kiểm tra user tồn tại
        let user = await User.findOne({ username });
        if (user) return res.status(400).json({ message: 'Người dùng đã tồn tại' });

        user = new User({ username, password });
        await user.save();

        res.status(201).json({ message: 'Đăng ký thành công' });
    } catch (err) {
        res.status(500).json({ message: 'Lỗi server', error: err.message });
    }
};

// Đăng nhập
exports.login = async (req, res) => {
    try {
        const { username, password } = req.body;

        const user = await User.findOne({ username });
        if (!user) return res.status(400).json({ message: 'Thông tin đăng nhập không chính xác' });

        const isMatch = await user.comparePassword(password);
        if (!isMatch) return res.status(400).json({ message: 'Thông tin đăng nhập không chính xác' });

        // Tạo JWT
        const token = jwt.sign(
            { userId: user._id, username: user.username },
            process.env.JWT_SECRET,
            { expiresIn: '1h' }
        );

        res.json({
            message: 'Đăng nhập thành công',
            token
        });
    } catch (err) {
        res.status(500).json({ message: 'Lỗi server', error: err.message });
    }
};

// Lấy thông tin cá nhân (Profile)
exports.getProfile = async (req, res) => {
    try {
        const user = await User.findById(req.user.userId).select('-password');
        res.json(user);
    } catch (err) {
        res.status(500).json({ message: 'Lỗi server' });
    }
};
```

#### 3.6. Routes (`src/routes/authRoutes.js`)
```javascript
const express = require('express');
const router = express.Router();
const authController = require('../controllers/authController');
const authMiddleware = require('../middlewares/auth');

// Public routes
router.post('/register', authController.register);
router.post('/login', authController.login);

// Protected route
router.get('/profile', authMiddleware, authController.getProfile);

module.exports = router;
```

#### 3.7. Cấu hình App (`src/app.js`)
```javascript
const express = require('express');
const authRoutes = require('./routes/authRoutes');

const app = express();

// Middleware xử lý JSON
app.use(express.json());

// Routes
app.use('/api/auth', authRoutes);

// Error handling middleware tập trung
app.use((err, req, res, next) => {
    console.error(err.stack);
    res.status(500).json({ message: 'Đã xảy ra lỗi hệ thống!' });
});

module.exports = app;
```

#### 3.8. Entry Point (`server.js`)
```javascript
require('dotenv').config();
const app = require('./src/app');
const connectDB = require('./src/config/db');

const PORT = process.env.PORT || 5000;

// Kết nối Database trước khi khởi chạy server
connectDB().then(() => {
    app.listen(PORT, () => {
        console.log(`🚀 Server đang chạy tại: http://localhost:${PORT}`);
    });
});
```

### 4. Hướng dẫn kiểm thử (Testing)

1. **Đăng ký (POST `/api/auth/register`):**
   - Body: `{"username": "dev_user", "password": "password123"}`
   - Kết quả: 201 Created.

2. **Đăng nhập (POST `/api/auth/login`):**
   - Body: `{"username": "dev_user", "password": "password123"}`
   - Kết quả: Trả về `token`.

3. **Truy cập Route Bảo mật (GET `/api/auth/profile`):**
   - Header: `Authorization: Bearer <token_vừa_nhận_được>`
   - Kết quả: Trả về thông tin User (không kèm mật khẩu).

### 5. Các điểm nổi bật theo thiết kế:
- **Bảo mật:** Sử dụng `bcryptjs` để băm mật khẩu và `jsonwebtoken` cho cơ chế Stateless Authentication.
- **Tách biệt:** Logic xử lý (Controller) tách biệt hoàn toàn với định nghĩa tuyến đường (Router).
- **Middleware:** Token được kiểm tra tại lớp middleware trước khi vào Controller xử lý dữ liệu nhạy cảm.
- **Clean Code:** Sử dụng `mongoose.pre('save')` để đảm bảo mật khẩu luôn được băm tự động.

