dev.code:
Chào bạn, tôi là **Dev Agent**. Dựa trên bản thiết kế chi tiết mà bạn đã cung cấp, tôi sẽ triển khai mã nguồn cho hệ thống **Express JWT Authentication Service**.

Hệ thống sẽ được cấu trúc theo mô hình phân lớp (Layered Architecture) để đảm bảo tính bảo trì và mở rộng.

### 1. Cấu trúc thư mục (Project Structure)
```text
express-jwt-auth/
├── src/
│   ├── config/
│   │   └── db.js          # Kết nối MongoDB
│   ├── controllers/
│   │   └── authController.js # Xử lý logic đăng ký/đăng nhập
│   ├── middlewares/
│   │   ├── authMiddleware.js # Xác thực JWT
│   │   └── errorMiddleware.js # Xử lý lỗi tập trung
│   ├── models/
│   │   └── User.js        # Mongoose Schema & Bcrypt logic
│   ├── routes/
│   │   └── authRoutes.js   # Định nghĩa các endpoints
│   └── app.js             # Cấu hình Express
├── .env                   # Biến môi trường
├── package.json
└── server.js              # Điểm khởi chạy hệ thống
```

---

### 2. Triển khai mã nguồn

#### Bước 1: Khởi tạo Project & Cài đặt thư viện
```bash
npm init -y
npm install express mongoose jsonwebtoken bcryptjs dotenv cors
```

#### Bước 2: Cấu hình biến môi trường (`.env`)
```env
PORT=5000
MONGO_URI=mongodb://localhost:27017/express-jwt-auth
JWT_SECRET=your_super_secret_key_12345
NODE_ENV=development
```

#### Bước 3: Model Người dùng (`src/models/User.js`)
Sử dụng `bcryptjs` để băm mật khẩu tự động trước khi lưu.

```javascript
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

const userSchema = new mongoose.Schema({
  username: {
    type: String,
    required: [true, 'Vui lòng cung cấp username'],
    unique: true,
    trim: true,
    minlength: [3, 'Username phải ít nhất 3 ký tự']
  },
  password: {
    type: String,
    required: [true, 'Vui lòng cung cấp mật khẩu'],
    minlength: [6, 'Mật khẩu phải ít nhất 6 ký tự']
  }
}, { timestamps: true });

// Middleware của Mongoose: Mã hóa mật khẩu trước khi lưu
userSchema.pre('save', async function(next) {
  if (!this.isModified('password')) return next();

  const salt = await bcrypt.genSalt(10);
  this.password = await bcrypt.hash(this.password, salt);
  next();
});

// Method so sánh mật khẩu
userSchema.methods.comparePassword = async function(candidatePassword) {
  return await bcrypt.compare(candidatePassword, this.password);
};

module.exports = mongoose.model('User', userSchema);
```

#### Bước 4: Middleware Xác thực & Lỗi (`src/middlewares/`)

**Xác thực JWT (`authMiddleware.js`):**
```javascript
const jwt = require('jsonwebtoken');

const protect = async (req, res, next) => {
  let token;

  if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
    try {
      token = req.headers.authorization.split(' ')[1];
      const decoded = jwt.verify(token, process.env.JWT_SECRET);

      // Gắn thông tin user vào request để các route sau sử dụng
      req.user = decoded;
      next();
    } catch (error) {
      res.status(401);
      next(new Error('Không có quyền truy cập, token không hợp lệ'));
    }
  }

  if (!token) {
    res.status(401);
    next(new Error('Không có token, quyền truy cập bị từ chối'));
  }
};

module.exports = { protect };
```

**Xử lý lỗi tập trung (`errorMiddleware.js`):**
```javascript
const errorHandler = (err, req, res, next) => {
  const statusCode = res.statusCode === 200 ? 500 : res.statusCode;

  res.status(statusCode).json({
    success: false,
    message: err.message,
    stack: process.env.NODE_ENV === 'development' ? err.stack : null,
  });
};

module.exports = { errorHandler };
```

#### Bước 5: Controller xử lý Logic (`src/controllers/authController.js`)
```javascript
const User = require('../models/User');
const jwt = require('jsonwebtoken');

const generateToken = (id) => {
  return jwt.sign({ id }, process.env.JWT_SECRET, { expiresIn: '30d' });
};

// @desc    Đăng ký người dùng
// @route   POST /api/auth/register
exports.register = async (req, res, next) => {
  try {
    const { username, password } = req.body;

    const userExists = await User.findOne({ username });
    if (userExists) {
      res.status(400);
      throw new Error('Người dùng đã tồn tại');
    }

    const user = await User.create({ username, password });

    res.status(201).json({
      success: true,
      data: {
        _id: user._id,
        username: user.username,
        token: generateToken(user._id)
      }
    });
  } catch (error) {
    next(error);
  }
};

// @desc    Đăng nhập
// @route   POST /api/auth/login
exports.login = async (req, res, next) => {
  try {
    const { username, password } = req.body;

    const user = await User.findOne({ username });

    if (user && (await user.comparePassword(password))) {
      res.json({
        success: true,
        data: {
          _id: user._id,
          username: user.username,
          token: generateToken(user._id)
        }
      });
    } else {
      res.status(401);
      throw new Error('Username hoặc mật khẩu không đúng');
    }
  } catch (error) {
    next(error);
  }
};

// @desc    Lấy profile (Protected)
exports.getMe = async (req, res) => {
  const user = await User.findById(req.user.id).select('-password');
  res.json({ success: true, data: user });
};
```

#### Bước 6: Định nghĩa Routes (`src/routes/authRoutes.js`)
```javascript
const express = require('express');
const router = express.Router();
const { register, login, getMe } = require('../controllers/authController');
const { protect } = require('../middlewares/authMiddleware');

router.post('/register', register);
router.post('/login', login);
router.get('/me', protect, getMe);

module.exports = router;
```

#### Bước 7: Thiết lập App & Server (`src/app.js` & `server.js`)

**`src/app.js`:**
```javascript
const express = require('express');
const cors = require('cors');
const authRoutes = require('./routes/authRoutes');
const { errorHandler } = require('./middlewares/errorMiddleware');

const app = express();

app.use(cors());
app.use(express.json());

// Routes
app.use('/api/auth', authRoutes);

// Error Middleware
app.use(errorHandler);

module.exports = app;
```

**`server.js`:**
```javascript
require('dotenv').config();
const mongoose = require('mongoose');
const app = require('./src/app');

const PORT = process.env.PORT || 5000;

// Kết nối Database & Start Server
mongoose.connect(process.env.MONGO_URI)
  .then(() => {
    console.log('✅ Đã kết nối MongoDB');
    app.listen(PORT, () => console.log(`🚀 Server đang chạy tại port ${PORT}`));
  })
  .catch((err) => {
    console.error('❌ Lỗi kết nối Database:', err.message);
    process.exit(1);
  });
```

