dev.code:
Chào bạn, tôi là Dev Agent. Dựa trên bản thiết kế hệ thống mà bạn cung cấp, tôi sẽ triển khai mã nguồn chi tiết cho dự án **express-jwt-mongodb-auth**.

Tôi sẽ xây dựng ứng dụng theo cấu trúc thư mục đã đề xuất để đảm bảo tính module hóa.

### 1. Khởi tạo dự án và cài đặt Dependencies

Đầu tiên, hãy tạo thư mục dự án và cài đặt các thư viện cần thiết:

```bash
mkdir express-jwt-auth
cd express-jwt-auth
npm init -y
npm install express mongoose jsonwebtoken bcryptjs dotenv
npm install --save-dev nodemon
```

### 2. Cấu trúc mã nguồn

#### 2.1. File `.env` (Cấu hình môi trường)
```env
PORT=5000
MONGODB_URI=mongodb://localhost:27017/express_auth_db
JWT_SECRET=your_super_secret_key_12345
JWT_EXPIRE=1h
```

#### 2.2. `src/config/db.js` (Kết nối Database)
```javascript
const mongoose = require('mongoose');

const connectDB = async () => {
    try {
        const conn = await mongoose.connect(process.env.MONGODB_URI);
        console.log(`MongoDB Connected: ${conn.connection.host}`);
    } catch (error) {
        console.error(`Error: ${error.message}`);
        process.exit(1);
    }
};

module.exports = connectDB;
```

#### 2.3. `src/models/User.js` (User Schema & Password Hashing)
```javascript
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

const userSchema = new mongoose.Schema({
    username: {
        type: String,
        required: [true, 'Please add a username'],
        unique: true,
        trim: true
    },
    password: {
        type: String,
        required: [true, 'Please add a password'],
        minlength: 6,
        select: false // Không trả về password mặc định khi query
    },
    createdAt: {
        type: Date,
        default: Date.now
    }
});

// Middleware: Băm mật khẩu trước khi lưu
userSchema.pre('save', async function(next) {
    if (!this.isModified('password')) {
        next();
    }
    const salt = await bcrypt.genSalt(10);
    this.password = await bcrypt.hash(this.password, salt);
});

// Method: Kiểm tra mật khẩu
userSchema.methods.matchPassword = async function(enteredPassword) {
    return await bcrypt.compare(enteredPassword, this.password);
};

module.exports = mongoose.model('User', userSchema);
```

#### 2.4. `src/middlewares/authMiddleware.js` (Xác thực JWT)
```javascript
const jwt = require('jsonwebtoken');
const User = require('../models/User');

const protect = async (req, res, next) => {
    let token;

    // Kiểm tra header Authorization (Bearer Token)
    if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
        try {
            token = req.headers.authorization.split(' ')[1];

            // Giải mã token
            const decoded = jwt.verify(token, process.env.JWT_SECRET);

            // Gắn thông tin user vào request (loại bỏ password)
            req.user = await User.findById(decoded.id);

            next();
        } catch (error) {
            res.status(401).json({ status: 'error', message: 'Not authorized, token failed' });
        }
    }

    if (!token) {
        res.status(401).json({ status: 'error', message: 'Not authorized, no token' });
    }
};

module.exports = { protect };
```

#### 2.5. `src/middlewares/errorMiddleware.js` (Xử lý lỗi tập trung)
```javascript
const errorHandler = (err, req, res, next) => {
    const statusCode = res.statusCode === 200 ? 500 : res.statusCode;

    res.status(statusCode).json({
        status: 'error',
        message: err.message,
        stack: process.env.NODE_ENV === 'production' ? null : err.stack,
    });
};

module.exports = { errorHandler };
```

#### 2.6. `src/controllers/authController.js` (Logic nghiệp vụ)
```javascript
const User = require('../models/User');
const jwt = require('jsonwebtoken');

// Tạo Token
const generateToken = (id) => {
    return jwt.sign({ id }, process.env.JWT_SECRET, {
        expiresIn: process.env.JWT_EXPIRE
    });
};

// @desc    Đăng ký người dùng
// @route   POST /api/auth/register
exports.register = async (req, res, next) => {
    try {
        const { username, password } = req.body;

        const userExists = await User.findOne({ username });
        if (userExists) {
            res.status(400);
            throw new Error('User already exists');
        }

        const user = await User.create({ username, password });

        res.status(201).json({
            status: 'success',
            token: generateToken(user._id)
        });
    } catch (error) {
        next(error);
    }
};

// @desc    Đăng nhập
// @route   POST /api/auth/login
exports.login = async (req, res, next) => {
    try {
        const { username, password } = req.body;

        const user = await User.findOne({ username }).select('+password');

        if (user && (await user.matchPassword(password))) {
            res.json({
                status: 'success',
                token: generateToken(user._id)
            });
        } else {
            res.status(401);
            throw new Error('Invalid username or password');
        }
    } catch (error) {
        next(error);
    }
};

// @desc    Lấy Profile (Route bảo vệ)
// @route   GET /api/auth/profile
exports.getProfile = async (req, res, next) => {
    try {
        const user = await User.findById(req.user._id);
        res.json({
            status: 'success',
            data: user
        });
    } catch (error) {
        next(error);
    }
};
```

#### 2.7. `src/routes/authRoutes.js` (Định nghĩa Route)
```javascript
const express = require('express');
const router = express.Router();
const { register, login, getProfile } = require('../controllers/authController');
const { protect } = require('../middlewares/authMiddleware');

router.post('/register', register);
router.post('/login', login);
router.get('/profile', protect, getProfile);

module.exports = router;
```

#### 2.8. `src/app.js` (Khởi tạo App)
```javascript
const express = require('express');
const dotenv = require('dotenv');
const connectDB = require('./config/db');
const authRoutes = require('./routes/authRoutes');
const { errorHandler } = require('./middlewares/errorMiddleware');

// Load env vars
dotenv.config();

// Connect to database
connectDB();

const app = express();

// Body parser
app.use(express.json());

// Routes
app.use('/api/auth', authRoutes);

// Centralized Error Handler
app.use(errorHandler);

const PORT = process.env.PORT || 5000;

app.listen(PORT, () => {
    console.log(`Server running in mode on port ${PORT}`);
});
```

### 3. Hướng dẫn chạy hệ thống

1.  **Cấu hình Database:** Đảm bảo bạn đã cài đặt MongoDB và đang chạy ở `localhost:27017` (hoặc thay đổi URL trong `.env`).
2.  **Chạy server:**
    ```bash
    # Chạy bình thường
    node src/app.js

    # Hoặc dùng nodemon để tự reload khi sửa code
    npx nodemon src/app.js
    ```
3.  **Kiểm thử API (Postman):**
    *   **Đăng ký:** POST `http://localhost:5000/api/auth/register` với body JSON `{ "username": "dev_user", "password": "password123" }`.
    *   **Đăng nhập:** POST `http://localhost:5000/api/auth/login` với cùng thông tin trên. Hệ thống sẽ trả về một `token`.
    *   **Truy cập Profile:** GET `http://localhost:5000/api/auth/profile`. Thêm Header: `Authorization: Bearer <token_vừa_nhận_được>`.

Hệ thống này đã hiện thực đầy đủ các yêu cầu trong thiết kế: Layered Architecture, Bảo mật mật khẩu, Xác thực JWT, và Xử lý lỗi tập trung.

